<?php
if ( ! defined( 'ABSPATH' ) ) { exit; }
class VH360_Studio_Bible_Admin {
    public function __construct(){add_action('admin_menu',array($this,'menu'),30);add_action('admin_enqueue_scripts',array($this,'assets'));}
    public function menu(){ $parent = menu_page_url( 'vh360-studio-settings', false ) ? 'vh360-studio-settings' : 'options-general.php'; add_submenu_page($parent,__('Bible Library','videohub360-studio'),__('Bible Library','videohub360-studio'),'manage_options','vh360-studio-bible',array($this,'render'));}
    public function assets($hook){if(false===strpos($hook,'vh360-studio-bible'))return;$p='assets/admin/studio-bible-admin.js';wp_enqueue_script('vh360-studio-bible-admin',VH360_STUDIO_PLUGIN_URL.$p,array(),VH360_STUDIO_VERSION.'-'.filemtime(VH360_STUDIO_PLUGIN_DIR.$p),true);wp_localize_script('vh360-studio-bible-admin','vh360StudioBibleAdmin',array('restRoot'=>esc_url_raw(rest_url('vh360-studio/v1')),'nonce'=>wp_create_nonce('wp_rest'),'strings'=>array('uploading'=>__('Uploading…','videohub360-studio'),'requestFailed'=>__('Request failed.','videohub360-studio'))));}
    public function render(){ $repo=new VH360_Studio_Bible_Repository(); echo '<div class="wrap"><h1>'.esc_html__('Bible Library','videohub360-studio').'</h1><table class="widefat"><thead><tr><th>'.esc_html__('Translation','videohub360-studio').'</th><th>'.esc_html__('Abbreviation','videohub360-studio').'</th><th>'.esc_html__('Language','videohub360-studio').'</th><th>'.esc_html__('Status','videohub360-studio').'</th><th>'.esc_html__('Books','videohub360-studio').'</th><th>'.esc_html__('Verses','videohub360-studio').'</th><th>'.esc_html__('Dataset','videohub360-studio').'</th><th>'.esc_html__('Imported','videohub360-studio').'</th><th>'.esc_html__('Attribution required','videohub360-studio').'</th><th>'.esc_html__('Source','videohub360-studio').'</th><th>'.esc_html__('License','videohub360-studio').'</th></tr></thead><tbody>'; foreach($repo->list_all_translations() as $tr){echo '<tr><td>'.esc_html($tr['name']).'</td><td>'.esc_html($tr['abbreviation']).'</td><td>'.esc_html($tr['language']).'</td><td>'.esc_html($tr['status']).'</td><td>'.esc_html($tr['bookCount']).'</td><td>'.esc_html($tr['verseCount']).'</td><td>'.esc_html($tr['datasetVersion']).'</td><td>'.esc_html($tr['importedAt']).'</td><td>'.esc_html($tr['attributionRequired']?__('Yes','videohub360-studio'):__('No','videohub360-studio')).'</td><td>'.esc_html($tr['sourceName']).'</td><td>'.esc_html($tr['licenseName']).'</td></tr>';} echo '</tbody></table><h2>'.esc_html__('Import translation','videohub360-studio').'</h2><form id="vh360-bible-import-form" enctype="multipart/form-data">'; $fields=array('translationKey'=>__('Translation key','videohub360-studio'),'name'=>__('Translation name','videohub360-studio'),'abbreviation'=>__('Abbreviation','videohub360-studio'),'language'=>__('Language','videohub360-studio'),'sourceName'=>__('Dataset source','videohub360-studio'),'sourceUrl'=>__('Source URL','videohub360-studio'),'licenseName'=>__('License name','videohub360-studio'),'licenseUrl'=>__('License URL','videohub360-studio'),'datasetVersion'=>__('Dataset version','videohub360-studio')); echo '<p><label>'.esc_html__('CSV file','videohub360-studio').'<br><input type="file" name="file" accept=".csv,text/csv" required></label></p>'; foreach($fields as $name=>$label){$req=in_array($name,array('translationKey','name','abbreviation','language','sourceName','licenseName','datasetVersion'),true)?' required':''; echo '<p><label>'.esc_html($label).'<br><input name="'.esc_attr($name).'"'.$req.'></label></p>'; } echo '<p><label>'.esc_html__('Attribution','videohub360-studio').'<br><textarea name="attribution"></textarea></label></p><p><label><input type="checkbox" name="attributionRequired" value="1"> '.esc_html__('Attribution is required by this license.','videohub360-studio').'</label></p><p><label><input type="checkbox" name="permissionConfirmed" value="1" required> '.esc_html__('I confirm permission to use this file.','videohub360-studio').'</label></p><button class="button button-primary">'.esc_html__('Import translation','videohub360-studio').'</button></form><pre id="vh360-bible-import-progress" aria-live="polite"></pre></div>';}
}
